/**
 * 批量操作模块
 *
 * @file admin/src/modules/lottery/composables/batch-operations.js
 * @description P3优先级 - 批量操作工具（配额赠送、状态切换、预算调整等）
 * @version 1.0.0
 * @date 2026-01-29
 */

import { logger } from '../../../utils/logger.js'
import { LOTTERY_ENDPOINTS } from '../../../api/lottery/index.js'
import { buildQueryString } from '../../../api/base.js'
import { UserAPI } from '../../../api/user.js'

/**
 * 批量操作状态
 * @returns {Object} 状态对象
 */
export function useBatchOperationsState() {
  return {
    // 批量操作相关
    /** @type {boolean} 显示批量操作面板 */
    showBatchOperationsPanel: false,
    /** @type {string} 当前批量操作类型 */
    currentBatchOperation: '', // quota-grant, campaign-status, budget-adjust
    /** @type {boolean} 正在执行批量操作 */
    executingBatchOperation: false,

    // 批量赠送每日配额（手机号主导，对应后端 bonus_draw_count）
    /** @type {Object} 批量赠送表单 */
    batchQuotaGrantForm: {
      lottery_campaign_id: '',
      mobiles: '',
      bonus_count: 1,
      reason: '',
      _custom_reason: ''
    },
    /** @type {Object|null} 批量手机号解析结果 */
    batchResolveResult: null,

    // 批量活动状态切换
    /** @type {Object} 批量状态切换表单 */
    batchCampaignStatusForm: {
      lottery_campaign_ids: [],
      target_status: 'active', // active, paused, ended
      reason: ''
    },

    // 批量预算调整
    /** @type {Object} 批量预算调整表单 */
    batchBudgetAdjustForm: {
      lottery_campaign_ids: [],
      adjustment_type: 'increase', // increase, decrease, set
      amount: 0,
      reason: ''
    },

    // 批量操作结果
    /** @type {Object|null} 批量操作结果 */
    batchOperationResult: null,

    // 批量操作日志
    /** @type {Array<Object>} 批量操作日志列表 */
    batchOperationLogs: [],
    /** @type {boolean} 日志加载状态 */
    loadingBatchLogs: false,
    /** @type {Object} 日志分页 */
    batchLogsPagination: {
      page: 1,
      page_size: 10,
      total_count: 0,
      total_pages: 0
    }
  }
}

/**
 * 批量操作方法
 * @returns {Object} 方法对象
 */
export function useBatchOperationsMethods() {
  return {
    /**
     * 打开批量操作面板
     * @param {string} operationType - 操作类型
     */
    openBatchOperationsPanel(operationType = 'quota-grant') {
      this.currentBatchOperation = operationType
      this.showBatchOperationsPanel = true
      this.batchOperationResult = null
      this.resetBatchForms()
    },

    /**
     * 关闭批量操作面板
     */
    closeBatchOperationsPanel() {
      this.showBatchOperationsPanel = false
      this.currentBatchOperation = ''
      this.batchOperationResult = null
    },

    /**
     * 重置批量操作表单
     */
    resetBatchForms() {
      this.batchQuotaGrantForm = {
        lottery_campaign_id: '',
        mobiles: '',
        bonus_count: 1,
        reason: '',
        _custom_reason: ''
      }
      this.batchResolveResult = null
      this.batchCampaignStatusForm = {
        lottery_campaign_ids: [],
        target_status: 'active',
        reason: ''
      }
      this.batchBudgetAdjustForm = {
        lottery_campaign_ids: [],
        adjustment_type: 'increase',
        amount: 0,
        reason: ''
      }
    },

    /**
     * 执行批量赠送每日配额（调用后端 B6 quota-grant 接口）
     * 后端实际操作：LotteryQuotaService.addBonusDrawCount → 更新 bonus_draw_count
     */
    async executeBatchQuotaGrant() {
      const form = this.batchQuotaGrantForm

      // 验证
      if (!form.lottery_campaign_id) {
        this.showError('请选择活动')
        return
      }
      if (!form.mobiles.trim()) {
        this.showError('请输入手机号列表')
        return
      }
      if (!form.bonus_count || form.bonus_count < 1) {
        this.showError('请输入有效的赠送次数')
        return
      }
      // 处理自定义原因
      const reason =
        form.reason === '__custom__' ? (form._custom_reason || '').trim() : form.reason.trim()

      if (!reason) {
        this.showError('请选择或输入赠送原因')
        return
      }

      // 解析手机号列表（支持逗号、换行分隔）
      const mobiles = form.mobiles
        .split(/[,\n]+/)
        .map(m => m.trim())
        .filter(m => m.length > 0)

      if (mobiles.length === 0) {
        this.showError('手机号列表不能为空')
        return
      }

      if (mobiles.length > 100) {
        this.showError('单次最多支持100个用户')
        return
      }

      // 逐个 resolve 手机号 → user_id（跳过失败项）
      this.executingBatchOperation = true
      this.batchResolveResult = null

      try {
        const resolvedUserIds = []
        const failedMobiles = []

        for (const mobile of mobiles) {
          if (!/^1\d{10}$/.test(mobile)) {
            failedMobiles.push(mobile)
            continue
          }
          try {
            const result = await UserAPI.resolveUser({ mobile })
            if (result.success && result.data?.user_id) {
              resolvedUserIds.push(result.data.user_id)
            } else {
              failedMobiles.push(mobile)
            }
          } catch {
            failedMobiles.push(mobile)
          }
        }

        // 显示解析结果
        this.batchResolveResult = {
          success_count: resolvedUserIds.length,
          failed_count: failedMobiles.length,
          failed_mobiles: failedMobiles
        }

        if (resolvedUserIds.length === 0) {
          this.showError('所有手机号解析失败，无法执行赠送')
          return
        }

        // 提交成功解析的 user_ids（后端字段名: lottery_campaign_id）
        const response = await this.apiPost(
          LOTTERY_ENDPOINTS.BATCH_QUOTA_GRANT,
          {
            lottery_campaign_id: parseInt(form.lottery_campaign_id),
            user_ids: resolvedUserIds,
            bonus_count: parseInt(form.bonus_count),
            reason
          },
          { showLoading: true }
        )

        if (response?.success) {
          this.batchOperationResult = response.data
          const msg =
            failedMobiles.length > 0
              ? `批量赠送完成：成功 ${response.data.success_count}/${mobiles.length}（跳过 ${failedMobiles.length} 个无效手机号）`
              : `批量赠送完成：成功 ${response.data.success_count}/${response.data.total_count}`
          this.showSuccess(msg)
          logger.info('[BatchOps] 批量赠送成功', response.data)
        } else {
          this.showError('批量赠送失败: ' + (response?.message || '未知错误'))
        }
      } catch (error) {
        logger.error('[BatchOps] 批量赠送失败:', error)
        this.showError('批量赠送失败: ' + (error.message || '网络错误'))
      } finally {
        this.executingBatchOperation = false
      }
    },

    /**
     * 执行批量活动状态切换
     */
    async executeBatchCampaignStatus() {
      const form = this.batchCampaignStatusForm

      if (!form.lottery_campaign_ids || form.lottery_campaign_ids.length === 0) {
        this.showError('请选择至少一个活动')
        return
      }
      if (!form.target_status) {
        this.showError('请选择目标状态')
        return
      }
      if (!form.reason.trim()) {
        this.showError('请输入操作原因')
        return
      }

      this.executingBatchOperation = true
      try {
        const response = await this.apiPost(
          LOTTERY_ENDPOINTS.BATCH_CAMPAIGN_STATUS,
          {
            lottery_campaign_ids: form.lottery_campaign_ids.map(id => parseInt(id)),
            target_status: form.target_status,
            reason: form.reason.trim()
          },
          { showLoading: true }
        )

        if (response?.success) {
          this.batchOperationResult = response.data
          this.showSuccess(
            `批量状态切换完成：成功 ${response.data.success_count}/${response.data.total_count}`
          )
          logger.info('[BatchOps] 批量状态切换成功', response.data)
          // 刷新活动列表
          await this.loadCampaigns?.()
        } else {
          this.showError('批量状态切换失败: ' + (response?.message || '未知错误'))
        }
      } catch (error) {
        logger.error('[BatchOps] 批量状态切换失败:', error)
        this.showError('批量状态切换失败: ' + (error.message || '网络错误'))
      } finally {
        this.executingBatchOperation = false
      }
    },

    /**
     * 执行批量预算调整
     */
    async executeBatchBudgetAdjust() {
      const form = this.batchBudgetAdjustForm

      if (!form.lottery_campaign_ids || form.lottery_campaign_ids.length === 0) {
        this.showError('请选择至少一个活动')
        return
      }
      if (!form.adjustment_type) {
        this.showError('请选择调整类型')
        return
      }
      if (form.amount === undefined || form.amount === null) {
        this.showError('请输入调整金额')
        return
      }
      if (!form.reason.trim()) {
        this.showError('请输入操作原因')
        return
      }

      // 后端期望 adjustments 数组：每个活动一条调整记录
      const adjustments = form.lottery_campaign_ids.map(id => ({
        lottery_campaign_id: parseInt(id),
        adjustment_type: form.adjustment_type,
        amount: parseFloat(form.amount)
      }))

      this.executingBatchOperation = true
      try {
        const response = await this.apiPost(
          LOTTERY_ENDPOINTS.BATCH_BUDGET_ADJUST,
          {
            adjustments,
            reason: form.reason.trim()
          },
          { showLoading: true }
        )

        if (response?.success) {
          this.batchOperationResult = response.data
          this.showSuccess(
            `批量预算调整完成：成功 ${response.data.success_count}/${response.data.total_count}`
          )
          logger.info('[BatchOps] 批量预算调整成功', response.data)
        } else {
          this.showError('批量预算调整失败: ' + (response?.message || '未知错误'))
        }
      } catch (error) {
        logger.error('[BatchOps] 批量预算调整失败:', error)
        this.showError('批量预算调整失败: ' + (error.message || '网络错误'))
      } finally {
        this.executingBatchOperation = false
      }
    },

    /**
     * 加载批量操作日志
     */
    async loadBatchOperationLogs() {
      this.loadingBatchLogs = true
      try {
        const params = {
          page: this.batchLogsPagination.page,
          page_size: this.batchLogsPagination.page_size
        }
        const queryString = buildQueryString(params)
        const response = await this.apiGet(
          `${LOTTERY_ENDPOINTS.BATCH_OPERATION_LOGS}${queryString}`,
          {},
          { showLoading: false }
        )

        if (response?.success) {
          this.batchOperationLogs = response.data.logs || []
          this.batchLogsPagination = response.data.pagination || this.batchLogsPagination
          logger.info('[BatchOps] 批量操作日志加载成功')
        } else {
          this.showError('加载批量操作日志失败')
        }
      } catch (error) {
        logger.error('[BatchOps] 加载批量操作日志失败:', error)
        this.showError('加载批量操作日志失败')
      } finally {
        this.loadingBatchLogs = false
      }
    },

    /**
     * 切换活动选中状态（用于批量操作）
     * @param {number} campaignId - 活动ID
     */
    toggleCampaignSelection(campaignId) {
      const index = this.batchCampaignStatusForm.lottery_campaign_ids.indexOf(campaignId)
      if (index > -1) {
        this.batchCampaignStatusForm.lottery_campaign_ids.splice(index, 1)
      } else {
        this.batchCampaignStatusForm.lottery_campaign_ids.push(campaignId)
      }
      // 同步到预算调整表单
      this.batchBudgetAdjustForm.lottery_campaign_ids = [
        ...this.batchCampaignStatusForm.lottery_campaign_ids
      ]
    },

    /**
     * 全选/取消全选活动
     * @param {boolean} selectAll - 是否全选
     */
    toggleAllCampaignsSelection(selectAll) {
      if (selectAll) {
        const allIds = this.campaigns.map(c => c.lottery_campaign_id)
        this.batchCampaignStatusForm.lottery_campaign_ids = allIds
        this.batchBudgetAdjustForm.lottery_campaign_ids = [...allIds]
      } else {
        this.batchCampaignStatusForm.lottery_campaign_ids = []
        this.batchBudgetAdjustForm.lottery_campaign_ids = []
      }
    },

    /**
     * 检查活动是否被选中
     * @param {number} campaignId - 活动ID
     * @returns {boolean} 是否选中
     */
    isCampaignSelected(campaignId) {
      return this.batchCampaignStatusForm.lottery_campaign_ids.includes(campaignId)
    },

    /**
     * 获取批量操作类型的中文显示名称
     * 对应后端 BatchOperationLog.OPERATION_TYPE_NAMES 字典
     * @param {string} operation_type - 后端字段 operation_type 值
     * @returns {string} 中文显示名
     */
    getBatchOperationTypeDisplay(operation_type) {
      // 与后端 BatchOperationLog.OPERATION_TYPE_NAMES 保持一致
      const names = {
        quota_grant_batch: '批量赠送每日配额',
        preset_batch: '批量设置干预规则',
        redemption_verify_batch: '批量核销确认',
        campaign_status_batch: '批量活动状态切换',
        budget_adjust_batch: '批量预算调整'
      }
      return names[operation_type] || operation_type
    },

    /**
     * 格式化批量操作时间
     * @param {string} isoString - ISO时间字符串
     * @returns {string} 格式化时间
     */
    formatBatchOperationTime(isoString) {
      if (!isoString) return '-'
      const date = new Date(isoString)
      return date.toLocaleString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false,
        timeZone: 'Asia/Shanghai'
      })
    }
  }
}

export default { useBatchOperationsState, useBatchOperationsMethods }
